import{_ as i,o as a,c as t,ag as r}from"./chunks/framework.ByAj6Cie.js";const h=JSON.parse('{"title":"Switchboards","description":"","frontmatter":{},"headers":[],"relativePath":"es/power-systems/equipment/switchboards.md","filePath":"es/power-systems/equipment/switchboards.md"}'),o={name:"es/power-systems/equipment/switchboards.md"};function s(n,e,l,c,d,p){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="switchboards" tabindex="-1">Switchboards <a class="header-anchor" href="#switchboards" aria-label="Permalink to &quot;Switchboards&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Switchboards are assemblies used to distribute low voltage power within industrial and commercial facilities.</p><p>They serve as central distribution points where incoming power is divided into multiple outgoing feeders.</p><p>Switchboards typically operate at low voltage and handle high current levels.</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>The purpose of switchboards is to:</p><ul><li>Distribute low voltage power to different areas or systems</li><li>Provide centralized control and protection of multiple feeders</li><li>Organize electrical distribution in a structured and accessible way</li><li>Enable safe operation and maintenance of power circuits</li></ul><p>They act as the main interface between incoming low voltage supply and downstream distribution.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>Power enters the switchboard from a transformer or upstream distribution equipment.</p><p>Inside the switchboard, power is distributed through:</p><ul><li>Main incoming breaker or switch</li><li>Busbars that carry power across the assembly</li><li>Feeder breakers that supply outgoing circuits</li></ul><p>Each feeder is protected by its own device, allowing individual circuits to be isolated without affecting the entire system.</p><p>Measurement and monitoring devices may also be included to track current, voltage, and energy consumption.</p><h2 id="applications" tabindex="-1">Applications <a class="header-anchor" href="#applications" aria-label="Permalink to &quot;Applications&quot;">​</a></h2><p>Switchboards are used in:</p><ul><li>Main low voltage distribution points in industrial facilities</li><li>Supplying sub distribution panels and motor control centers</li><li>Feeding large groups of loads such as production areas</li><li>Commercial buildings and infrastructure systems</li></ul><p>They are typically installed close to the main transformer or incoming supply.</p><h2 id="key-considerations" tabindex="-1">Key Considerations <a class="header-anchor" href="#key-considerations" aria-label="Permalink to &quot;Key Considerations&quot;">​</a></h2><ul><li><p><strong>Current rating</strong><br> Must handle total load demand and future expansion</p></li><li><p><strong>Short circuit rating</strong><br> Equipment must withstand available fault current</p></li><li><p><strong>Number of feeders</strong><br> Should allow proper load distribution and spare capacity</p></li><li><p><strong>Protection devices</strong><br> Selection of breakers affects coordination and safety</p></li><li><p><strong>Physical layout</strong><br> Accessibility, cable entry, and space for maintenance are important</p></li><li><p><strong>Standards and compliance</strong><br> Must meet applicable electrical and safety requirements</p></li></ul><h2 id="practical-notes" tabindex="-1">Practical Notes <a class="header-anchor" href="#practical-notes" aria-label="Permalink to &quot;Practical Notes&quot;">​</a></h2><ul><li>Switchboards handle high currents, requiring proper ventilation and spacing</li><li>Poor load balancing can lead to overheating of busbars and feeders</li><li>Clear labeling simplifies operation and troubleshooting</li><li>Including spare feeder positions reduces future modification effort</li><li>Proper torque on connections is critical to avoid failures</li></ul>',23)])])}const b=i(o,[["render",s]]);export{h as __pageData,b as default};
